Factor = tuple[tuple[str, ...], dict[tuple[str, ...], float]]


def _factor_multiply(f1: Factor, f2: Factor) -> Factor:
    """Multiply two factors over their shared variables."""
    vars1, tab1 = f1
    vars2, tab2 = f2
    result_vars = tuple(sorted(set(vars1) | set(vars2)))
